@font-face {
    font-family: 'Ahem';
    src: url('file:///Users/henryluo/Projects/lambda-test/layout/data/support/ahem3.ttf') format('truetype');
    font-weight: normal;
    font-style: normal;
}

.container {
  width: 400px;
  font-family: Ahem;
  font-size: 20px;
  line-height: 1.5em;
}
#test {
    color: green;
}
#test-float-left {
  shape-outside: inset(50% 50% 50% 50%);
  float: left;
  width: 200px;
  height: 200px;
}
#failure {
    color: red;
    z-index: -1;
}
#test, #failure {
    position: absolute;
    top: 70px;
}
#square{
    position: absolute;
    top: 70px;
    width: 196px;
    height: 196px;
    border: 1px solid black;
    z-index: 10;
}
